MOD = 10**9 + 7

def factorial(n, mod=MOD):
    """Compute n! mod mod"""
    if n < 0:
        return 0
    result = 1
    for i in range(2, n + 1):
        result = (result * i) % mod
    return result

def pow_mod(base, exp, mod=MOD):
    """Compute base^exp mod mod using binary exponentiation"""
    if exp < 0:
        return 0
    result = 1
    base = base % mod
    while exp > 0:
        if exp & 1:
            result = (result * base) % mod
        base = (base * base) % mod
        exp >>= 1
    return result

def mod_inverse(a, mod=MOD):
    """Compute modular inverse using Fermat's little theorem"""
    return pow_mod(a, mod - 2, mod)

