    """Compute C(n, k) mod mod"""
    if k < 0 or k > n:
        return 0
    if k == 0 or k == n:
        return 1
    if k > n - k:
        k = n - k
    num = factorial(n, mod)
    den = (factorial(k, mod) * factorial(n - k, mod)) % mod
    return (num * mod_inverse(den, mod)) % mod

