        # C(n-2, k-2) * (k-2)! = P(n-2, k-2)
        ways_choose = comb(n - 2, k - 2)

        # (k-2)! for ordering
        order_factorial = factorial(k - 2)

        # C(m-1, k-2) for weight distribution
        ways_weights = comb(m - 1, k - 2)

        # n^(n-k-1) * k for tree structure
        if n - k - 1 >= 0:
            ways_tree = (pow_mod(n, n - k - 1) * k) % MOD
        else:
            ways_tree = k

        term = (ways_choose * order_factorial) % MOD
        term = (term * ways_weights) % MOD
        term = (term * ways_tree) % MOD
        result = (result + term) % MOD

    return result

